# Module containing data processing classes and functions
from types_module import IValue, Priority, Point3D

@abstract
class DataProcessor:
    label: str
    priority: Priority

    def __init__(self, label: str, priority: Priority):
        self.label = label
        self.priority = priority

    @abstract
    def process(self, data: int) -> str:
        ...

    @virtual
    def get_label(self) -> str:
        return self.label

class IntProcessor(DataProcessor, IValue[int]):
    multiplier: int

    def __init__(self, label: str, priority: Priority, mult: int):
        super().__init__(label, priority)
        self.multiplier = mult

    @override
    def process(self, data: int) -> str:
        result: int = data * self.multiplier
        result_str: str = str(result)
        return "Result: " + result_str

    @override
    def get_value(self) -> int:
        return self.multiplier

def create_default_point() -> Point3D:
    return Point3D(0.0, 0.0, 0.0)

def get_priority_level(p: Priority) -> str:
    return p.name

def format_processor_info(proc: IntProcessor) -> str:
    # Accept the concrete type instead of the abstract base
    priority_val: int = proc.priority.value
    priority_str: str = str(priority_val)
    return proc.label + " [" + priority_str + "]"
